/* ═══ 1. 상태값 ═══ */
const D={user:{name:'학생',streak:0,days:0,titles:3},routines:[{id:1,name:'기상 후 스트레칭',time:'07:00',done:false,streak:0},{id:2,name:'영어 단어 10개',time:'08:00',done:false,streak:0},{id:3,name:'수학 문제 5개',time:'16:00',done:false,streak:0}],todos:[],activityLog:{},challenges:{},careerValues:['growth','stability','money','meaning','challenge','freedom','people','creative'],journalEntries:[],stratDeck:{idx:0,ratings:{},completed:[]},evals:[],ddays:[],events:{},rpg:{level:1,exp:0,statPoints:0,stats:{str:1,dex:1,con:1,wis:1},expLog:[],totalExpEarned:0},favorites:[]};

/* ═══ RPG 시스템 ═══ */
var EXP_TABLE={login:{amount:10,label:'오늘의 접속'},routine_one:{amount:15,label:'루틴 완료'},routine_all:{amount:30,label:'루틴 전체 완료!'},diagnosis:{amount:50,label:'진단 검사 완료'},journal:{amount:20,label:'진로 저널 작성'},eval:{amount:25,label:'자기평가 기록'},braindump:{amount:30,label:'브레인덤프 완료'},strategy:{amount:20,label:'전략 카드 실행'},challenge:{amount:10,label:'챌린지 체크'},values:{amount:15,label:'가치관 정렬'}};
var STAT_META={
  str:{code:'STR',name:'전략',emoji:'⚔️',color:'#7C5CE0',bg:'#F4F0FE',desc:'학습 전략을 세우고 실행하는 능력이야.\n공부할 때 "어떻게 하면 효율적인지" 아는 힘!\n\n이 스탯이 높으면:\n• 자기만의 공부법이 있어\n• 시간을 효율적으로 써\n• 시험 전략을 잘 세워',act:'전략 카드 실행, 브레인덤프 완료'},
  dex:{code:'DEX',name:'탐색',emoji:'🧭',color:'#4A8FE7',bg:'#ECF3FD',desc:'다양한 진로를 탐색하고 나만의 방향을 찾아가는 능력이야.\n\n이 스탯이 높으면:\n• 관심 분야가 명확해\n• 직업 세계를 넓게 알아\n• 진로 결정에 자신감이 있어',act:'진로 저널 작성, 가치관 정렬, 직업 탐색'},
  con:{code:'CON',name:'지속',emoji:'💪',color:'#2DB67D',bg:'#EDFAF5',desc:'좋은 습관을 꾸준히 유지하는 체력이야.\n매일 조금씩 반복하는 힘!\n\n이 스탯이 높으면:\n• 루틴을 꾸준히 실천해\n• 작심삼일 없이 버텨\n• 66일 챌린지를 완주할 수 있어',act:'루틴 완료, 66일 챌린지 체크'},
  wis:{code:'WIS',name:'성찰',emoji:'🔮',color:'#F0A030',bg:'#FEF8ED',desc:'나를 돌아보고 객관적으로 평가하는 지혜야.\n메타인지의 핵심!\n\n이 스탯이 높으면:\n• 자기 상태를 정확히 파악해\n• 뭘 모르는지 알고 있어\n• 감정을 잘 다스릴 수 있어',act:'자기평가 기록, 진단 검사 완료'}
};
var STAT_KEYS=['str','dex','con','wis'];

function initRPG(){var r=D.rpg;if(!r){D.rpg={level:1,exp:0,statPoints:0,stats:{str:1,dex:1,con:1,wis:1},expLog:[],totalExpEarned:0};r=D.rpg}if(!r.stats)r.stats={str:1,dex:1,con:1,wis:1};if(!r.expLog)r.expLog=[];if(r.totalExpEarned===undefined)r.totalExpEarned=0;if(r.statPoints===undefined)r.statPoints=0}
function expFor(lv){return lv*100}
function gainEXP(reason,opts){initRPG();var r=D.rpg,e=EXP_TABLE[reason];if(!e)return null;var today=new Date().toISOString().slice(0,10),allowM=opts&&opts.allowMultiple;if(!allowM&&r.expLog.some(function(l){return l.date===today&&l.reason===reason}))return null;r.exp+=e.amount;r.totalExpEarned+=e.amount;r.expLog.push({date:today,amount:e.amount,reason:reason});if(r.expLog.length>100)r.expLog=r.expLog.slice(-100);var lup=false,old=r.level;while(r.exp>=expFor(r.level)){r.exp-=expFor(r.level);r.level++;r.statPoints++;lup=true}return{gained:e.amount,label:e.label,leveledUp:lup,oldLevel:old,newLevel:r.level}}
function handleEXP(reason,opts){var result=gainEXP(reason,opts);if(!result)return;showExpToast('+'+result.gained+' EXP  '+result.label);renderStatCard();if(result.leveledUp)setTimeout(function(){showLvlBanner(result.newLevel)},500);SS.save()}

/* ═══ 스탯 카드 렌더 ═══ */
var radarOpen=false;
function renderStatCard(){initRPG();var r=D.rpg,needed=expFor(r.level),pct=needed>0?Math.min(100,Math.round(r.exp/needed*100)):0;var today=new Date().toISOString().slice(0,10);var todayExp=r.expLog.filter(function(l){return l.date===today}).reduce(function(s,l){return s+l.amount},0);
document.getElementById('scLvBadge').textContent=r.level;document.getElementById('scLvName').textContent=D.user.name||'학생';document.getElementById('scLvNum').textContent=r.level;
document.getElementById('scExpFill').style.width=pct+'%';document.getElementById('scExpNum').textContent=r.exp+' / '+needed;document.getElementById('scTodayExp').textContent=todayExp;
var ap=document.getElementById('scApBadge');ap.textContent=r.statPoints;ap.classList.toggle('has',r.statPoints>0);
if(radarOpen)drawRadar();drawStatBars()}

function drawRadar(){var svg=document.getElementById('radarSvg');var cx=100,cy=100,R=78;var s=D.rpg.stats;var angs=[-90,0,90,180];var colors=['#7C5CE0','#4A8FE7','#2DB67D','#F0A030'];
var highest=Math.max(s.str||1,s.dex||1,s.con||1,s.wis||1);var scale=Math.min(100,Math.max(20,Math.ceil(highest*1.4/10)*10));var h='';
for(var g=1;g<=4;g++){var gr=R*(g/4);var pts=angs.map(function(a){var rad=a*Math.PI/180;return(cx+gr*Math.cos(rad)).toFixed(1)+','+(cy+gr*Math.sin(rad)).toFixed(1)}).join(' ');h+='<polygon points="'+pts+'" fill="none" stroke="var(--bd)" stroke-width="0.6" opacity=".3"/>'}
angs.forEach(function(a){var rad=a*Math.PI/180;h+='<line x1="'+cx+'" y1="'+cy+'" x2="'+(cx+R*Math.cos(rad)).toFixed(1)+'" y2="'+(cy+R*Math.sin(rad)).toFixed(1)+'" stroke="var(--bd)" stroke-width="0.6" opacity=".3"/>'});
var ptsList=[];STAT_KEYS.forEach(function(k,i){var v=s[k]||1;var r2=R*(v/scale);var rad=angs[i]*Math.PI/180;ptsList.push({x:cx+r2*Math.cos(rad),y:cy+r2*Math.sin(rad)})});
var polyPts=ptsList.map(function(p){return p.x.toFixed(1)+','+p.y.toFixed(1)}).join(' ');
h+='<polygon points="'+polyPts+'" fill="var(--ac)" fill-opacity=".08" stroke="none"/>';
for(var i=0;i<4;i++){var next=(i+1)%4;h+='<line x1="'+ptsList[i].x.toFixed(1)+'" y1="'+ptsList[i].y.toFixed(1)+'" x2="'+ptsList[next].x.toFixed(1)+'" y2="'+ptsList[next].y.toFixed(1)+'" stroke="'+colors[i]+'" stroke-width="2" stroke-linecap="round"/>'}
svg.innerHTML=h;
var lb=document.getElementById('radarLabels');var positions=[{cls:'top',s:'top:0;left:50%;transform:translateX(-50%)'},{cls:'right',s:'right:0;top:50%;transform:translateY(-50%)'},{cls:'bottom',s:'bottom:0;left:50%;transform:translateX(-50%)'},{cls:'left',s:'left:0;top:50%;transform:translateY(-50%)'}];
lb.innerHTML=STAT_KEYS.map(function(k,i){var m=STAT_META[k],p=positions[i],v=D.rpg.stats[k]||1;return'<div class="sc-rl '+p.cls+'" style="'+p.s+';color:'+colors[i]+'">'+m.code+' <span style="font-weight:900">'+v+'</span></div>'}).join('')}

function toggleRadar(){radarOpen=!radarOpen;var area=document.getElementById('scRadarArea');var arrow=document.getElementById('scToggleArrow');var text=document.getElementById('scRadarToggleText');if(radarOpen){area.style.display='flex';arrow.classList.add('open');text.textContent='스탯 차트 접기';drawRadar()}else{area.style.display='none';arrow.classList.remove('open');text.textContent='스탯 차트 보기'}}

function drawStatBars(){var el=document.getElementById('scStatBars');var s=D.rpg.stats;var hasPts=D.rpg.statPoints>0;
el.innerHTML=STAT_KEYS.map(function(k){var m=STAT_META[k],v=s[k]||1;var pct=Math.min(100,v).toFixed(0);return'<div class="sc-stat-row"><div class="sc-sr-code" style="color:'+m.color+'">'+m.code+'</div><div class="sc-sr-bar-wrap"><div class="sc-sr-bar" style="width:'+pct+'%;background:linear-gradient(90deg,'+m.color+'99,'+m.color+')"></div></div><div class="sc-sr-val">'+v+'</div><button class="sc-sr-plus'+(hasPts?' active':'')+'" onclick="allocStat(\''+k+'\')">+</button><button class="sc-sr-q" onclick="openSP(\''+k+'\')">?</button></div>'}).join('')}

function allocStat(k){var r=D.rpg;if(r.statPoints<=0)return;if((r.stats[k]||0)>=100){showExpToast(STAT_META[k].code+' 이미 최대야!');return}r.statPoints--;r.stats[k]++;renderStatCard();showExpToast('+1 '+STAT_META[k].code+' 투자!');SS.save()}
function openSP(k){var m=STAT_META[k],v=D.rpg.stats[k]||1;document.getElementById('spCode').textContent=m.code;document.getElementById('spCode').style.color=m.color;document.getElementById('spName').textContent=m.name;document.getElementById('spVal').textContent=v;document.getElementById('spVal').style.color=m.color;document.getElementById('spBody').textContent=m.desc;document.getElementById('spAct').innerHTML='⚡ EXP 획득 활동: '+m.act;document.getElementById('spOverlay').classList.add('on')}
function closeSP(){document.getElementById('spOverlay').classList.remove('on')}

var _expToastT=null;
function showExpToast(text){var el=document.getElementById('expToast');if(!el)return;document.getElementById('expToastText').textContent=text;el.classList.add('show');clearTimeout(_expToastT);_expToastT=setTimeout(function(){el.classList.remove('show')},2000)}
function showLvlBanner(lv){var el=document.getElementById('lvlBanner');if(!el)return;document.getElementById('lvlBannerSub').textContent='Lv.'+lv+' 달성! 스탯 포인트 획득!';el.classList.add('show');setTimeout(function(){el.classList.remove('show')},2500)}

/* ═══ 직업 매트릭스 ═══ */
var JM_CAT_MAP={'경영·회계·사무 관련직':'경영/금융','금융·보험 관련직':'경영/금융','교육 및 자연과학, 사회과학 연구관련직':'교육/연구','법률·경찰· 소방·교도 관련직':'법/행정','보건·의료 관련직':'의료/보건','정보통신 관련직':'IT/공학','전기·전자 관련직':'IT/공학','기계 관련직':'IT/공학','건설 관련직':'건설/환경','환경·인쇄·목재· 가구·공예 및 생산단순직':'건설/환경','문화·예술· 디자인·방송 관련직':'문화/예술','사회복지 관련직':'사회/복지','영업 및 판매 관련직':'사회/복지','경비 관련직':'사회/복지','농림어업 관련직':'자연/농업','식품가공 관련직':'자연/농업','화학 관련직':'자연/농업','재료 관련직 (금속·유리·점토·시멘트)':'자연/농업','미용·숙박·여행· 오락·스포츠 관련직':'관광/스포츠','음식 서비스 관련직':'관광/스포츠','운전 및 운송 관련직':'운송/물류'};
var JM_CATS=['전체','경영/금융','교육/연구','법/행정','의료/보건','IT/공학','건설/환경','문화/예술','사회/복지','자연/농업','관광/스포츠','운송/물류'];
var JM_CAT_EMOJI={'전체':'📋','경영/금융':'💼','교육/연구':'📚','법/행정':'⚖️','의료/보건':'🏥','IT/공학':'💻','건설/환경':'🏗️','문화/예술':'🎨','사회/복지':'🤝','자연/농업':'🌿','관광/스포츠':'⚽','운송/물류':'🚀'};
var JM_DIST_COLORS={'인문계열':'#7C5CE0','사회계열':'#4A8FE7','교육계열':'#2DB67D','공학계열':'#E85454','자연계열':'#F0A030','의학계열':'#E76B9A','예체능계열':'#5CC9E0'};
var jmCurCat='전체',jmFavOnly=false,jmCompareMode=false,jmCompareList=[],jmDetailJob=null;

function initJobMatrix(){var el=document.getElementById('jmCats');if(!el)return;el.innerHTML=JM_CATS.map(function(c){return'<button class="pill'+(c==='전체'?' on':'')+'" data-jmcat="'+c+'" onclick="setJmCat(\''+c.replace(/'/g,"\\'")+'\',this)">'+(JM_CAT_EMOJI[c]||'')+' '+c+'</button>'}).join('');filterJobs()}
function setJmCat(cat,btn){jmCurCat=cat;document.querySelectorAll('#jmCats .pill').forEach(function(b){b.classList.toggle('on',b.dataset.jmcat===cat)});filterJobs()}
function toggleFavFilter(){jmFavOnly=!jmFavOnly;document.getElementById('jmFavBtn').classList.toggle('on',jmFavOnly);filterJobs()}
function filterJobs(){if(typeof ALL_JOBS==='undefined')return;var q=(document.getElementById('jmSearch')?document.getElementById('jmSearch').value:'').trim().toLowerCase();
var results=ALL_JOBS.filter(function(j){if(jmCurCat!=='전체'){var tag=JM_CAT_MAP[j.c]||'기타';if(tag!==jmCurCat)return false}if(jmFavOnly&&!(D.favorites||[]).includes(j.j))return false;if(!q)return true;if(j.j.toLowerCase().includes(q))return true;if(j.c.toLowerCase().includes(q))return true;var syns=(typeof JOB_SYNONYMS!=='undefined'?JOB_SYNONYMS[j.j]:null)||[];return syns.some(function(s){return s.toLowerCase().includes(q)})});
renderJobList(results)}

function renderJobList(jobs){var el=document.getElementById('jmList');var cnt=document.getElementById('jmCount');if(!el)return;cnt.textContent=jobs.length+'개 직업';
if(!jobs.length){el.innerHTML='<div class="jm-empty">검색 결과가 없어요<br>다른 키워드로 찾아보세요</div>';return}
el.innerHTML=jobs.map(function(j){var tag=JM_CAT_MAP[j.c]||'기타';var isFav=(D.favorites||[]).includes(j.j);var mc=j.m?j.m.length:0;var ej=j.j.replace(/'/g,"\\'");
if(jmCompareMode){var isSel=jmCompareList.includes(j.j);return'<div class="jm-job" onclick="toggleCompareSelect(\''+ej+'\')" style="'+(isSel?'border:2px solid var(--ac);background:var(--acg)':'')+'"><div class="jm-job-emoji">'+(isSel?'☑️':'⬜')+'</div><div class="jm-job-info"><div class="jm-job-name">'+j.j+'</div><div class="jm-job-cat">'+tag+'</div></div><div style="font-size:11px;color:var(--ac);font-weight:600">학과 '+mc+'개</div></div>'}
return'<div class="jm-job" onclick="openJobDetail(\''+ej+'\')"><div class="jm-job-emoji">'+(JM_CAT_EMOJI[tag]||'📋')+'</div><div class="jm-job-info"><div class="jm-job-name">'+j.j+'</div><div class="jm-job-cat">'+tag+' · 관련 학과 '+mc+'개</div></div><button class="jm-job-fav" onclick="event.stopPropagation();toggleFav(\''+ej+'\')">'+(isFav?'❤️':'🤍')+'</button><div class="jm-job-arr">›</div></div>'}).join('')}

function toggleFav(name){if(!D.favorites)D.favorites=[];var i=D.favorites.indexOf(name);if(i>=0)D.favorites.splice(i,1);else D.favorites.push(name);filterJobs();SS.save()}

function openJobDetail(name){var job=ALL_JOBS.find(function(j){return j.j===name});if(!job)return;jmDetailJob=job;var tag=JM_CAT_MAP[job.c]||'기타';var isFav=(D.favorites||[]).includes(job.j);
document.getElementById('jdTitle').textContent=job.j;document.getElementById('jdFav').textContent=isFav?'❤️':'🤍';
var distMap={};(job.m||[]).forEach(function(m){var c=m.c||'기타';distMap[c]=(distMap[c]||0)+1});var totalM=(job.m||[]).length||1;
var distArr=Object.keys(distMap).map(function(k){return{name:k,count:distMap[k],pct:Math.round(distMap[k]/totalM*100)}}).sort(function(a,b){return b.count-a.count});
var body=document.getElementById('jdBody');body.innerHTML='<div class="jd-card"><div class="jd-cat-badge">'+(JM_CAT_EMOJI[tag]||'')+' '+tag+'</div><div class="jd-source">커리어넷 대학학과+직업 매트릭스 기반 데이터야.<br>이 학과를 졸업하면 '+job.j+'(으)로 진출할 수 있어!</div></div>'
+'<div class="jd-card"><div class="jd-card-title">계열 분포</div>'+distArr.map(function(d){var color=JM_DIST_COLORS[d.name]||'var(--t3)';return'<div class="jd-dist-row"><div class="jd-dist-label">'+d.name.replace('계열','')+'</div><div class="jd-dist-bar"><div class="jd-dist-fill" style="width:'+d.pct+'%;background:'+color+'"></div></div><div class="jd-dist-pct">'+d.pct+'%</div></div>'}).join('')+'</div>'
+'<div class="jd-card"><div class="jd-card-title">관련 학과 ('+totalM+'개)</div><div class="jd-majors">'+(job.m||[]).map(function(m){return'<div class="jd-major">'+m.n+'</div>'}).join('')+'</div></div>';
var related=ALL_JOBS.filter(function(j2){return j2.c===job.c&&j2.j!==job.j}).slice(0,6);
if(related.length){body.innerHTML+='<div class="jd-card"><div class="jd-card-title">같은 분야 직업</div><div class="jd-related">'+related.map(function(r){var ej=r.j.replace(/'/g,"\\'");return'<div class="jd-rel-card" onclick="openJobDetail(\''+ej+'\')"><div class="jd-rel-emoji">'+(JM_CAT_EMOJI[JM_CAT_MAP[r.c]||'기타']||'📋')+'</div><div class="jd-rel-name">'+r.j+'</div></div>'}).join('')+'</div></div>'}
document.getElementById('jdOverlay').classList.add('on')}
function closeJobDetail(){document.getElementById('jdOverlay').classList.remove('on')}
function toggleDetailFav(){if(!jmDetailJob)return;toggleFav(jmDetailJob.j);document.getElementById('jdFav').textContent=(D.favorites||[]).includes(jmDetailJob.j)?'❤️':'🤍'}

function toggleCompareMode(){jmCompareMode=!jmCompareMode;jmCompareList=[];document.getElementById('jmCompareMode').classList.toggle('on',jmCompareMode);document.getElementById('jmCompareBar').classList.toggle('on',jmCompareMode);updateCompareBar();filterJobs()}
function toggleCompareSelect(name){if(!jmCompareMode)return;var i=jmCompareList.indexOf(name);if(i>=0)jmCompareList.splice(i,1);else{if(jmCompareList.length>=3)return;jmCompareList.push(name)}updateCompareBar();filterJobs()}
function updateCompareBar(){document.getElementById('jmCompareBtn').disabled=jmCompareList.length<2;document.getElementById('jmCompareText').textContent=jmCompareList.length===0?'비교할 직업을 선택해':jmCompareList.join(' vs ')+' ('+jmCompareList.length+'/3)'}
function showCompare(){if(jmCompareList.length<2)return;var jobs=jmCompareList.map(function(n){return ALL_JOBS.find(function(j){return j.j===n})}).filter(Boolean);
var html='<div class="jc-vs">'+jobs.map(function(j){return j.j}).join(' vs ')+'</div><div class="jc-grid">';
jobs.forEach(function(j){var tag=JM_CAT_MAP[j.c]||'기타';html+='<div class="jc-col"><div class="jc-col-name">'+j.j+'</div><div class="jc-col-cat">'+tag+'</div><div class="jc-col-num">'+(j.m||[]).length+'</div><div class="jc-col-label">관련 학과</div></div>'});html+='</div>';
var allDists=Object.keys(JM_DIST_COLORS);html+='<div class="jd-card"><div class="jd-card-title">계열 분포 비교</div>';
allDists.forEach(function(dist){var hasAny=jobs.some(function(j){return(j.m||[]).some(function(m){return m.c===dist})});if(!hasAny)return;html+='<div style="font-size:12px;font-weight:600;color:var(--t2);margin:8px 0 4px">'+dist+'</div>';jobs.forEach(function(j){var cnt=(j.m||[]).filter(function(m){return m.c===dist}).length;var total=(j.m||[]).length||1;var pct=Math.round(cnt/total*100);html+='<div class="jd-dist-row"><div class="jd-dist-label" style="width:80px;font-size:11px">'+j.j.slice(0,6)+'</div><div class="jd-dist-bar"><div class="jd-dist-fill" style="width:'+pct+'%;background:'+(JM_DIST_COLORS[dist]||'var(--t3)')+'"></div></div><div class="jd-dist-pct">'+pct+'%</div></div>'})});html+='</div>';
if(jobs.length===2){var m1=(jobs[0].m||[]).map(function(m){return m.n}),m2=(jobs[1].m||[]).map(function(m){return m.n});var shared=m1.filter(function(n){return m2.includes(n)});if(shared.length){html+='<div class="jc-shared"><div class="jc-shared-title">공통 학과 <div class="jc-shared-badge">'+shared.length+'개</div></div><div style="font-size:12px;color:var(--t3);margin-bottom:10px">이 학과 가면 두 직업 다 가능해!</div><div class="jd-majors">'+shared.map(function(n){return'<div class="jd-major" style="border-color:var(--gn);color:var(--gn)">'+n+'</div>'}).join('')+'</div></div>'}}
document.getElementById('jcBody').innerHTML=html;document.getElementById('jcOverlay').classList.add('on')}
function closeCompare(){document.getElementById('jcOverlay').classList.remove('on')}

