const STRATS=[{id:1,d:'mo',t:'"왜 공부하는지" 적기',b:'내가 공부하는 진짜 이유를 구체적으로 적어봐.'},{id:2,d:'mo',t:'오늘의 학습 목표 1개 선언',b:'오늘 끝낼 구체적인 목표를 하나만 정해봐.'},{id:3,d:'mo',t:'완수 후 보상 정하기',b:'할 일을 다 끝내면 뭘로 보상할지 미리 정해둬.'},{id:4,d:'mo',t:'작은 성공 3개 떠올리기',b:'최근에 해낸 작은 일 3개를 적어봐.'},{id:5,d:'mo',t:'진행률 시각화하기',b:'할 일 목록을 적고 하나씩 줄 그으며 지워봐.'},{id:6,d:'mc',t:'"뭘 모르는지" 먼저 적기',b:'공부 시작 전에 모르는 것 3개를 적어봐.'},{id:7,d:'mc',t:'공부 후 요약 3줄 쓰기',b:'배운 핵심을 3줄로 요약해봐.'},{id:8,d:'mc',t:'자기에게 질문 3개 만들기',b:'배운 내용으로 시험 문제를 3개 만들어봐.'},{id:9,d:'mc',t:'어제 배운 것 떠올리기',b:'공부 전에 어제 뭘 배웠는지 3분간 떠올려봐.'},{id:10,d:'bh',t:'뽀모도로 25분 집중',b:'타이머 25분 설정 → 한 과목만 집중 → 5분 휴식.'},{id:11,d:'bh',t:'폰 다른 곳에 두기',b:'가장 효과적인 집중법은 폰을 눈에 안 보이게 하는 거야.'},{id:12,d:'bh',t:'2분 규칙 — 일단 시작',b:'하기 싫으면 "딱 2분만" 시작해봐.'},{id:13,d:'bh',t:'할 일 우선순위 정하기',b:'가장 중요한 1개를 골라 먼저 해치워.'},{id:14,d:'en',t:'책상 위 3가지만 남기기',b:'교과서, 필기구, 물 — 이 3가지만 남기고 나머지는 치워!'},{id:15,d:'en',t:'백색소음 틀기',b:'가사 없는 음악이나 빗소리를 틀어봐.'}];
const DNAME={mo:'동기조절',mc:'메타인지',bh:'행동조절',en:'환경조절'};
function renderSD(){var el=document.getElementById('sdBody');if(!el)return;var sd=D.stratDeck;var idx=sd.idx||0;if(idx>=STRATS.length)idx=0;var s=STRATS[idx];var rh=[1,2,3,4,5].map(function(n){return'<button class="sd-rb'+(sd.ratings[s.id]>=n?' on':'')+'" onclick="rateSt('+n+')">'+n+'</button>'}).join('');el.innerHTML='<div class="sd '+s.d+'"><div class="sd-domain '+s.d+'">'+DNAME[s.d]+'</div><div class="sd-title">'+s.t+'</div><div class="sd-desc">'+s.b+'</div><div class="sd-rate-label">이 전략이 도움이 됐어?</div><div class="sd-rate">'+rh+'</div><div class="sd-actions"><button class="sd-btn skip" onclick="skipSt()">건너뛰기</button><button class="sd-btn done" onclick="doneSt()">실행 완료 ✨</button></div><div class="sd-progress"><span>'+(idx+1)+' / '+STRATS.length+'</span><span>완료 '+(sd.completed?sd.completed.length:0)+'개</span></div></div>'}
function rateSt(n){D.stratDeck.ratings[STRATS[D.stratDeck.idx||0].id]=n;renderSD();SS.save()}
function skipSt(){D.stratDeck.idx=((D.stratDeck.idx||0)+1)%STRATS.length;renderSD();SS.save()}
function doneSt(){var sd=D.stratDeck,s=STRATS[sd.idx||0];if(!sd.completed)sd.completed=[];if(!sd.completed.includes(s.id))sd.completed.push(s.id);sd.idx=((sd.idx||0)+1)%STRATS.length;renderSD();handleEXP('strategy',{allowMultiple:true});SS.save()}

/* ═══ 가치관 ═══ */
const VALS=[{id:'growth',e:'🌱',n:'성장',d:'계속 배우고 발전'},{id:'stability',e:'🏠',n:'안정',d:'안정적 수입과 생활'},{id:'money',e:'💰',n:'보수',d:'높은 연봉과 경제적 자유'},{id:'meaning',e:'💙',n:'보람',d:'사회 기여와 의미 있는 일'},{id:'challenge',e:'🔥',n:'도전',d:'새로운 것에 도전'},{id:'freedom',e:'🕊️',n:'자율',d:'자유로운 환경'},{id:'people',e:'🤝',n:'관계',d:'좋은 사람들과 함께'},{id:'creative',e:'🎨',n:'창의',d:'아이디어를 실현'}];
function renderVals(){var w=document.getElementById('valWrap');if(!w)return;var order=D.careerValues||VALS.map(function(v){return v.id});w.innerHTML=order.map(function(vid,i){var v=VALS.find(function(x){return x.id===vid})||VALS[0];return'<div class="vc" draggable="true" data-val="'+v.id+'"><div class="vc-rank'+(i>=3?' dim':'')+'">'+(i+1)+'</div><div class="vc-emoji">'+v.e+'</div><div class="vc-info"><div class="vc-name">'+v.n+'</div><div class="vc-desc">'+v.d+'</div></div><div class="vc-handle">⠿</div></div>'}).join('');initDrag(w)}
function initDrag(w){var dEl=null;w.addEventListener('dragstart',function(e){dEl=e.target.closest('.vc');if(dEl)dEl.style.opacity='.4'});w.addEventListener('dragend',function(){if(dEl)dEl.style.opacity='';dEl=null;saveValOrder(w)});w.addEventListener('dragover',function(e){e.preventDefault();if(!dEl)return;var af=gAfter(w,e.clientY);if(af)w.insertBefore(dEl,af);else w.appendChild(dEl)});var tI=null;w.addEventListener('touchstart',function(e){tI=e.target.closest('.vc');if(tI)tI.style.opacity='.5'},{passive:true});w.addEventListener('touchmove',function(e){if(!tI)return;e.preventDefault();var af=gAfter(w,e.touches[0].clientY);if(af)w.insertBefore(tI,af);else w.appendChild(tI)},{passive:false});w.addEventListener('touchend',function(){if(tI){tI.style.opacity='';saveValOrder(w);tI=null}})}
function gAfter(c,y){return[].slice.call(c.querySelectorAll('.vc')).reduce(function(cl,ch){var b=ch.getBoundingClientRect(),o=y-b.top-b.height/2;return o<0&&o>cl.offset?{offset:o,element:ch}:cl},{offset:-Infinity}).element}
function saveValOrder(w){var cs=w.querySelectorAll('.vc');D.careerValues=[].slice.call(cs).map(function(c){return c.dataset.val});cs.forEach(function(c,i){var r=c.querySelector('.vc-rank');r.textContent=i+1;r.className='vc-rank'+(i>=3?' dim':'')});handleEXP('values');SS.save()}

/* ═══ 저널 ═══ */
function renderJournal(){var el=document.getElementById('jnList');if(!el)return;if(!D.journalEntries.length){el.innerHTML='<div class="empty" style="padding:24px"><div class="empty-text">첫 기록을 남겨보세요</div></div>';return}el.innerHTML=D.journalEntries.map(function(j){return'<div class="jn-entry"><div class="jn-date">'+j.date+'</div><div class="jn-text">'+j.text+'</div></div>'}).join('')}
function addJournal(){var inp=document.getElementById('jnInput');if(!inp)return;var t=inp.value.trim();if(!t)return;var now=new Date(),days=['일','월','화','수','목','금','토'];D.journalEntries.unshift({date:now.getFullYear()+'.'+(now.getMonth()+1)+'.'+now.getDate()+' ('+days[now.getDay()]+')',text:t});inp.value='';renderJournal();handleEXP('journal',{allowMultiple:true});SS.save()}

/* ═══ 루틴 ═══ */
function renderRoutines(){var el=document.getElementById('rtList');if(!el)return;var dn=D.routines.filter(function(r){return r.done}).length;document.getElementById('rtMeta').textContent=dn+'/'+D.routines.length+' 완료';if(!D.routines.length){el.innerHTML='<div class="empty" style="padding:20px"><div class="empty-text">루틴을 추가해보세요</div></div>';return}el.innerHTML=D.routines.map(function(r){return'<div class="rt-item"><button class="rt-ck'+(r.done?' dn':'')+'" onclick="togRoutine('+r.id+')">'+(r.done?'✓':'')+'</button><div style="flex:1"><div class="rt-name'+(r.done?' x':'')+'">'+r.name+'</div><div class="rt-time">'+r.time+'</div></div>'+(r.streak?'<div class="rt-streak">🔥 '+r.streak+'일</div>':'')+'</div>'}).join('');updateDonut()}
function togRoutine(id){var r=D.routines.find(function(x){return x.id===id});if(!r)return;r.done=!r.done;if(r.done){r.streak++;handleEXP('routine_one',{allowMultiple:true});if(D.routines.every(function(rt){return rt.done}))handleEXP('routine_all')}else{if(r.streak>0)r.streak--}renderRoutines();SS.save()}
function addRoutine(){var n=prompt('새 루틴 이름:');if(!n)return;D.routines.push({id:Date.now(),name:n,time:'16:00',done:false,streak:0});renderRoutines();SS.save()}

