const CHAL=[{id:'reading',e:'📚',n:'매일 10분 독서'},{id:'exercise',e:'💪',n:'매일 스트레칭'},{id:'vocab',e:'📝',n:'영어 단어 10개'},{id:'journal',e:'✍️',n:'하루 한 줄 일기'},{id:'tidy',e:'🧹',n:'잠자기 전 정리'}];
function renderChallenges(){var el=document.getElementById('chList');if(!el)return;el.innerHTML=CHAL.map(function(c){var d=D.challenges[c.id]||{days:[]};var cnt=d.days?d.days.length:0;var pct=Math.min(100,Math.round(cnt/66*100));return'<div class="ch'+(cnt>0?' on':'')+'" onclick="togChallenge(\''+c.id+'\')"><div class="ch-top"><div class="ch-emoji">'+c.e+'</div><div class="ch-name">'+c.n+'</div><div class="ch-pct">'+cnt+'/66</div></div><div class="prg"><div class="prg-fill" style="width:'+pct+'%"></div></div></div>'}).join('')}
function togChallenge(id){if(!D.challenges[id])D.challenges[id]={days:[]};var td=new Date().toISOString().slice(0,10);var i=D.challenges[id].days.indexOf(td);if(i>=0)D.challenges[id].days.splice(i,1);else{D.challenges[id].days.push(td);handleEXP('challenge',{allowMultiple:true})}renderChallenges();SS.save()}

/* ═══ 자기평가 ═══ */
var evData={mood:'',tags:[],scores:{cog:0,mot:0,beh:0,emo:0}};
function selMood(btn,mood){document.querySelectorAll('.ev-mood').forEach(function(b){b.classList.remove('on')});btn.classList.add('on');evData.mood=mood}
function togTag(btn){btn.classList.toggle('on');var t=btn.dataset.t;if(evData.tags.includes(t))evData.tags=evData.tags.filter(function(x){return x!==t});else evData.tags.push(t)}
function setEvScore(dim,val){evData.scores[dim]=val;var el=document.getElementById('ev'+dim.charAt(0).toUpperCase()+dim.slice(1));if(el)el.querySelectorAll('.ev-scale-btn').forEach(function(b,i){b.classList.toggle('on',i<val)})}
function initEvScales(){['Cog','Mot','Beh','Emo'].forEach(function(d){var el=document.getElementById('ev'+d);if(!el)return;var dim=d.toLowerCase();el.innerHTML=[1,2,3,4,5].map(function(n){return'<div class="ev-scale-item"><button class="ev-scale-btn" onclick="setEvScore(\''+dim+'\','+n+')">'+n+'</button><div class="ev-scale-label">'+(n===1?'낮음':n===5?'높음':'')+'</div></div>'}).join('')})}
function submitEval(){if(!evData.mood){alert('컨디션을 선택해줘!');return}var now=new Date();D.evals.unshift({date:now.getFullYear()+'.'+(now.getMonth()+1)+'.'+now.getDate()+' '+now.getHours()+':'+String(now.getMinutes()).padStart(2,'0'),mood:evData.mood,tags:[].concat(evData.tags),scores:Object.assign({},evData.scores),memo:document.getElementById('evMemo').value.trim()});evData={mood:'',tags:[],scores:{cog:0,mot:0,beh:0,emo:0}};document.querySelectorAll('.ev-mood,.ev-tag,.ev-scale-btn').forEach(function(b){b.classList.remove('on')});document.getElementById('evMemo').value='';handleEXP('eval');SS.save();closeSub()}

