const TITLES=[{id:'t01',e:'🌱',n:'첫 걸음',d:'앱 첫 접속',ck:function(){return true}},{id:'t02',e:'📝',n:'기록 시작',d:'자기평가 1회',ck:function(){return D.evals.length>=1}},{id:'t03',e:'🔥',n:'3일 연속',d:'3일 연속 접속',ck:function(){return D.user.streak>=3}},{id:'t04',e:'⚡',n:'7일 연속',d:'7일 연속 접속',ck:function(){return D.user.streak>=7}},{id:'t05',e:'💎',n:'30일 연속',d:'30일 연속 접속',ck:function(){return D.user.streak>=30}},{id:'t06',e:'👑',n:'60일 연속',d:'60일 연속 접속',ck:function(){return D.user.streak>=60}},{id:'t07',e:'🧠',n:'자기 발견',d:'K-SRL 진단 완료',ck:function(){return D.user.ksrlDone}},{id:'t08',e:'🧭',n:'방향 탐색',d:'홀랜드 검사 완료',ck:function(){return D.user.hollandDone}},{id:'t09',e:'🎯',n:'전략가',d:'전략 카드 5개 실행',ck:function(){return(D.stratDeck.completed||[]).length>=5}},{id:'t10',e:'🏆',n:'전략 달인',d:'전략 카드 10개 실행',ck:function(){return(D.stratDeck.completed||[]).length>=10}},{id:'t11',e:'✍️',n:'저널 입문',d:'진로 저널 3개',ck:function(){return D.journalEntries.length>=3}},{id:'t12',e:'📖',n:'저널 마스터',d:'진로 저널 10개',ck:function(){return D.journalEntries.length>=10}},{id:'t13',e:'📋',n:'루틴 시작',d:'루틴 1개 완수',ck:function(){return D.routines.some(function(r){return r.done})}},{id:'t14',e:'💪',n:'루틴 전사',d:'하루 루틴 전부 완수',ck:function(){return D.routines.length>0&&D.routines.every(function(r){return r.done})}},{id:'t15',e:'📊',n:'자기 성찰',d:'자기평가 5회',ck:function(){return D.evals.length>=5}},{id:'t16',e:'🔍',n:'메타인지 훈련',d:'자기평가 20회',ck:function(){return D.evals.length>=20}},{id:'t17',e:'💭',n:'브레인덤프 입문',d:'브레인덤프 1회',ck:function(){return Object.keys(D.events).length>=1}},{id:'t18',e:'📅',n:'계획의 달인',d:'일정 10개 이상',ck:function(){return Object.values(D.events).flat().length>=10}},{id:'t19',e:'🏅',n:'챌린지 도전',d:'66일 챌린지 시작',ck:function(){return Object.values(D.challenges).some(function(c){return c.days&&c.days.length>0})}},{id:'t20',e:'⭐',n:'챌린지 정복',d:'66일 챌린지 완주',ck:function(){return Object.values(D.challenges).some(function(c){return c.days&&c.days.length>=66})}},{id:'t21',e:'💖',n:'가치관 탐색',d:'가치관 정렬 완료',ck:function(){return D.careerValues&&D.careerValues.length>=8}},{id:'t22',e:'🗓️',n:'10일 활동',d:'누적 10일',ck:function(){return D.user.days>=10}},{id:'t23',e:'📆',n:'30일 활동',d:'누적 30일',ck:function(){return D.user.days>=30}},{id:'t24',e:'🎓',n:'100일 활동',d:'누적 100일',ck:function(){return D.user.days>=100}}];
function checkTitles(){if(!D.user.earnedTitles)D.user.earnedTitles=[];TITLES.forEach(function(t){if(!D.user.earnedTitles.includes(t.id)&&t.ck())D.user.earnedTitles.push(t.id)});D.user.titles=D.user.earnedTitles.length}
function renderTitles(){checkTitles();var earned=D.user.earnedTitles||[];document.getElementById('titlePreview').innerHTML=TITLES.slice(0,6).map(function(t){return'<div class="title-card'+(earned.includes(t.id)?'':' locked')+'"><div class="title-emoji">'+t.e+'</div><div class="title-name">'+t.n+'</div></div>'}).join('');var el=document.getElementById('titlesAll');if(el)el.innerHTML=TITLES.map(function(t){return'<div class="title-card'+(earned.includes(t.id)?'':' locked')+'" onclick="'+(earned.includes(t.id)?'setRepTitle(\''+t.id+'\')':'')+'"><div class="title-emoji">'+t.e+'</div><div class="title-name">'+t.n+'</div></div>'}).join('');document.getElementById('myTitleCnt').textContent=earned.length;var rep=TITLES.find(function(t){return t.id===D.user.repTitle})||TITLES.find(function(t){return earned.includes(t.id)})||{n:'탐험가'};document.getElementById('myTitle').textContent=rep.n}
function setRepTitle(id){D.user.repTitle=id;renderTitles();SS.save()}

