function renderRecords(){var sc=(D.stratDeck.completed||[]).length;document.getElementById('recStudyMt').textContent='전략 실행 '+sc+'개';document.getElementById('recCareerMt').textContent='저널 '+D.journalEntries.length+'개';var rd=D.routines.filter(function(r){return r.done}).length;document.getElementById('recHabitMt').textContent='루틴 '+rd+'/'+D.routines.length+' 완수';document.getElementById('recEvalMt').textContent='기록 '+D.evals.length+'개';
var MOODS={great:'😆 최고',good:'😊 좋아',normal:'😐 보통',bad:'😩 별로',worst:'😤 최악'};
var rs=document.getElementById('recStudy');if(rs){if(!sc)rs.innerHTML='<div class="empty"><div class="empty-text">아직 실행한 전략이 없어요</div></div>';else rs.innerHTML='<div class="card"><div style="font-size:15px;font-weight:700;margin-bottom:12px">실행한 전략 '+sc+'개</div>'+(D.stratDeck.completed||[]).map(function(id){var s=STRATS.find(function(x){return x.id===id});return s?'<div style="margin-bottom:6px"><div style="font-size:13px;font-weight:600">'+s.t+'</div><div style="font-size:11px;color:var(--t3)">'+DNAME[s.d]+'</div></div>':''}).join('')+'</div>'}
var rc=document.getElementById('recCareer');if(rc){if(!D.journalEntries.length)rc.innerHTML='<div class="empty"><div class="empty-text">아직 저널 기록이 없어요</div></div>';else rc.innerHTML=D.journalEntries.map(function(j){return'<div style="padding:12px 0;border-bottom:1px solid var(--bd)"><div style="font-size:11px;color:var(--t4);margin-bottom:4px">'+j.date+'</div><div style="font-size:14px;line-height:1.5">'+j.text+'</div></div>'}).join('')}
var rh=document.getElementById('recHabit');if(rh)rh.innerHTML='<div class="card"><div style="font-size:15px;font-weight:700;margin-bottom:12px">루틴 현황</div>'+D.routines.map(function(r){return'<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--bd)"><span style="font-size:14px">'+r.name+'</span><span style="font-size:13px;color:'+(r.done?'var(--gn)':'var(--t4)')+'">'+(r.done?'완료':'미완')+'</span></div>'}).join('')+'</div>';
var re=document.getElementById('recEval');if(re){if(!D.evals.length)re.innerHTML='<div class="empty"><div class="empty-text">아직 자기평가 기록이 없어요</div></div>';else re.innerHTML=D.evals.slice(0,20).map(function(ev){return'<div class="card" style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;margin-bottom:8px"><span style="font-size:11px;color:var(--t4)">'+ev.date+'</span><span style="font-size:16px">'+(MOODS[ev.mood]||ev.mood)+'</span></div>'+(ev.memo?'<div style="font-size:13px;color:var(--t2);margin-top:8px;padding-top:8px;border-top:1px solid var(--bd)">'+ev.memo+'</div>':'')+'</div>'}).join('')}}
function editProfile(){var name=prompt('닉네임:',D.user.name);if(name)D.user.name=name;var job=prompt('희망직업:',D.user.job||'');if(job!==null)D.user.job=job;var field=prompt('관심분야:',D.user.field||'');if(field!==null)D.user.field=field;updateHome();renderTitles();SS.save()}

