var OB_STEPS=[{ari:'안녕! 나는 아리야 👋\n너의 학습, 진로, 습관을 함께 관리해줄 AI 친구야!',type:'next'},{ari:'시작하려면 학교 코드를 알려줘!\n선생님이 알려주셨을 거야 😊',type:'school'},{ari:'반가워! 몇 학년 몇 반 몇 번이야?',type:'grade'},{ari:'좋아! 내가 너를 뭐라고 부르면 될까?\n별명이나 부르고 싶은 이름 아무거나 OK!',type:'nick'},{ari:'다음에 다시 만날 때 쓸 비밀번호를 만들어놓자!\n숫자 4~6자리로 해줘',type:'pw'},{ari:'혹시 관심 있는 분야가 있어?\n여러 개 골라도 돼!',type:'interests'},{ari:'장래 희망이 있으면 알려줘!\n아직 모르겠으면 패스해도 돼 ☺',type:'job'},{ari:'COMPLETE',type:'done'}];
function startOnboard(){var el=document.getElementById('authInner');var total=OB_STEPS.length-1;el.innerHTML='<div class="ob-header"><div class="ob-header-av">🤖</div><div class="ob-header-info"><div class="ob-header-name">아리</div><div class="ob-header-status">온라인</div></div></div><div class="ob-progress" id="obProg">'+Array(total).fill(0).map(function(_,i){return'<div class="ob-dot" id="obP'+i+'"></div>'}).join('')+'</div><div class="ob-messages" id="obMsgs"></div><div id="obInputArea"></div>';setTimeout(function(){obSendAri()},300)}
function obUpdateProgress(){var total=OB_STEPS.length-1;for(var i=0;i<total;i++){var d=document.getElementById('obP'+i);if(!d)continue;if(i<OB.step)d.className='ob-dot done';else if(i===OB.step)d.className='ob-dot on';else d.className='ob-dot'}}
function obSendAri(){var step=OB_STEPS[OB.step];if(!step||step.type==='done'){obShowDone();return}obUpdateProgress();var msgs=document.getElementById('obMsgs');var typing=document.createElement('div');typing.className='ob-typing';typing.id='obTyping';typing.innerHTML='<div class="ob-av-mini">🤖</div><div class="ob-typing-dots"><div class="ob-typing-dot"></div><div class="ob-typing-dot"></div><div class="ob-typing-dot"></div></div>';msgs.appendChild(typing);msgs.scrollTop=msgs.scrollHeight;setTimeout(function(){var t=document.getElementById('obTyping');if(t)t.remove();var msg=document.createElement('div');msg.className='ob-msg';msg.innerHTML='<div class="ob-av-mini">🤖</div><div class="ob-bubble">'+step.ari.replace(/\n/g,'<br>')+'</div>';msgs.appendChild(msg);msgs.scrollTop=msgs.scrollHeight;obShowInput(step)},800+Math.random()*400)}
function obAddUserMsg(text){var msgs=document.getElementById('obMsgs');var msg=document.createElement('div');msg.className='ob-msg user';msg.innerHTML='<div class="ob-bubble user">'+text+'</div>';msgs.appendChild(msg);msgs.scrollTop=msgs.scrollHeight}
function obShowInput(step){var area=document.getElementById('obInputArea');if(step.type==='next')area.innerHTML='<div class="ob-choices"><button class="ob-btn" onclick="obNext()">다음</button></div>';else if(step.type==='school')area.innerHTML='<div class="ob-input-bar"><div class="ob-input-inner"><input class="ob-input" id="obSchool" placeholder="학교 코드 입력" style="text-transform:uppercase"><button class="ob-send" onclick="obSchool()"><svg viewBox="0 0 24 24"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg></button></div><div id="obSchoolName" style="font-size:12px;color:var(--ac);min-height:16px;margin-top:4px;padding:0 4px"></div><div class="ob-error" id="obErr"></div></div>';else if(step.type==='grade')area.innerHTML='<div class="ob-choices"><div style="font-size:12px;color:var(--t3);margin-bottom:6px;text-align:center">'+OB.data.schoolName+'</div><div class="ob-select-row"><select class="ob-select" id="obGrade"><option value="">학년</option><option>1</option><option>2</option><option>3</option></select><select class="ob-select" id="obClass"><option value="">반</option>'+Array(20).fill(0).map(function(_,i){return'<option>'+(i+1)+'</option>'}).join('')+'</select><select class="ob-select" id="obNum"><option value="">번호</option>'+Array(40).fill(0).map(function(_,i){return'<option>'+(i+1)+'</option>'}).join('')+'</select></div><div class="ob-error" id="obErr"></div><button class="ob-btn" onclick="obGrade()">확인</button></div>';else if(step.type==='nick')area.innerHTML='<div class="ob-input-bar"><div class="ob-input-inner"><input class="ob-input" id="obNick" placeholder="닉네임 입력" maxlength="10"><button class="ob-send" onclick="obNick()"><svg viewBox="0 0 24 24"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg></button></div><div class="ob-error" id="obErr"></div></div>';else if(step.type==='pw')area.innerHTML='<div class="ob-choices"><input class="ob-input" id="obPw" type="password" placeholder="비밀번호 (숫자 4~6자리)" maxlength="6" inputmode="numeric" style="border-radius:24px;margin-bottom:6px"><input class="ob-input" id="obPw2" type="password" placeholder="비밀번호 확인" maxlength="6" inputmode="numeric" style="border-radius:24px"><div class="ob-error" id="obErr"></div><button class="ob-btn" onclick="obPw()">확인</button></div>';else if(step.type==='interests')area.innerHTML='<div class="ob-choices"><div class="ob-tags">'+INTEREST_TAGS.map(function(t){return'<button class="ob-tag" onclick="this.classList.toggle(\'on\')" data-t="'+t+'">'+t+'</button>'}).join('')+'</div><button class="ob-btn" onclick="obInterests()">선택 완료</button><button class="ob-btn-ghost" onclick="OB.data.interests=[];obAddUserMsg(\'나중에 선택할게\');obNext()">나중에</button></div>';else if(step.type==='job')area.innerHTML='<div class="ob-input-bar"><div class="ob-input-inner"><input class="ob-input" id="obJob" placeholder="예: AI 연구원, 의사..."><button class="ob-send" onclick="obJob()"><svg viewBox="0 0 24 24"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg></button></div><button class="ob-btn-ghost" onclick="OB.data.job=\'아직 탐색 중\';obAddUserMsg(\'아직 모르겠어\');obNext()" style="margin:4px 16px">아직 모르겠어</button></div>'}
function obShowDone(){var nm=OB.data.nick||'친구';var msgs=document.getElementById('obMsgs');var area=document.getElementById('obInputArea');var typing=document.createElement('div');typing.className='ob-typing';typing.id='obTyping';typing.innerHTML='<div class="ob-av-mini">🤖</div><div class="ob-typing-dots"><div class="ob-typing-dot"></div><div class="ob-typing-dot"></div><div class="ob-typing-dot"></div></div>';msgs.appendChild(typing);msgs.scrollTop=msgs.scrollHeight;setTimeout(function(){var t=document.getElementById('obTyping');if(t)t.remove();var msg=document.createElement('div');msg.className='ob-msg';msg.innerHTML='<div class="ob-av-mini">🤖</div><div class="ob-bubble">'+nm+'! 준비 완료! 🎉<br>이제 함께 성장의 여정을 시작하자!</div>';msgs.appendChild(msg);msgs.scrollTop=msgs.scrollHeight;obUpdateProgress();area.innerHTML='<div class="ob-choices"><button class="ob-btn" onclick="finishOnboard()">홈으로 가기 →</button></div>'},800)}
function obNext(){OB.step++;setTimeout(function(){obSendAri()},400)}
function obSchool(){var code=document.getElementById('obSchool').value.trim().toUpperCase();var info=SCHOOL_CODES[code];if(!info){document.getElementById('obErr').textContent='유효하지 않은 코드야!';return}OB.data.school=code;OB.data.schoolName=info.name;obAddUserMsg(code);OB_STEPS[2].ari='반가워! '+info.name+' 학생이구나! 😊\n몇 학년 몇 반 몇 번이야?';document.getElementById('obInputArea').innerHTML='';obNext()}
function obGrade(){var g=document.getElementById('obGrade').value,c=document.getElementById('obClass').value,n=document.getElementById('obNum').value;if(!g||!c||!n){document.getElementById('obErr').textContent='학년/반/번호를 모두 선택해줘!';return}var key=OB.data.school+'_'+g+'_'+c+'_'+n;if(localStorage.getItem('cu_'+key)){document.getElementById('obErr').textContent='이미 등록된 학번이야!';return}OB.data.grade=g;OB.data.cls=c;OB.data.num=n;obAddUserMsg(g+'학년 '+c+'반 '+n+'번');document.getElementById('obInputArea').innerHTML='';obNext()}
function obNick(){var nick=document.getElementById('obNick').value.trim();if(!nick){document.getElementById('obErr').textContent='닉네임을 입력해줘!';return}if(nick.length<1||nick.length>10){document.getElementById('obErr').textContent='1~10글자로 해줘!';return}var lower=nick.toLowerCase();if(BAD_WORDS.some(function(w){return lower.includes(w)})){document.getElementById('obErr').textContent='이 닉네임은 사용할 수 없어!';return}OB.data.nick=nick;obAddUserMsg(nick);OB_STEPS[4].ari=nick+'! 좋은 이름이다 😎\n다음에 다시 만날 때 쓸 비밀번호를 만들어놓자!\n숫자 4~6자리로 해줘';document.getElementById('obInputArea').innerHTML='';obNext()}
function obPw(){var pw=document.getElementById('obPw').value,pw2=document.getElementById('obPw2').value;if(!pw||pw.length<4||pw.length>6||!/^\d+$/.test(pw)){document.getElementById('obErr').textContent='숫자 4~6자리로 해줘!';return}if(pw!==pw2){document.getElementById('obErr').textContent='비밀번호가 일치하지 않아!';return}OB.data.pw=pw;obAddUserMsg('●●●●');document.getElementById('obInputArea').innerHTML='';obNext()}
function obInterests(){var sel=[].slice.call(document.querySelectorAll('.ob-tag.on')).map(function(b){return b.dataset.t});OB.data.interests=sel;obAddUserMsg(sel.length?sel.join(', '):'선택 안 함');document.getElementById('obInputArea').innerHTML='';obNext()}
function obJob(){var job=document.getElementById('obJob').value.trim();if(!job)return;OB.data.job=job;obAddUserMsg(job);document.getElementById('obInputArea').innerHTML='';obNext()}
function finishOnboard(){var key=OB.data.school+'_'+OB.data.grade+'_'+OB.data.cls+'_'+OB.data.num;D.user.name=OB.data.nick;D.user.pw=OB.data.pw;D.user.school=OB.data.schoolName;D.user.schoolCode=OB.data.school;D.user.grade=OB.data.grade;D.user.cls=OB.data.cls;D.user.num=OB.data.num;D.user.interests=OB.data.interests;D.user.job=OB.data.job;D.user.field=OB.data.interests.join(', ');AUTH.key=key;var dataJson=JSON.stringify(D);localStorage.setItem('cu_auth_key',key);localStorage.setItem('cu_'+key,dataJson);API.registerStudent(key,OB.data.school,OB.data.grade,OB.data.cls,OB.data.num,OB.data.nick,OB.data.pw,dataJson,function(r){},function(e){});var ov=document.getElementById('authOv');ov.classList.add('out');setTimeout(function(){ov.remove()},500);initApp()}

