var curTab='home';
function nav(t){var tabOrder=['home','contents','schedule','my'];var oldIdx=tabOrder.indexOf(curTab);var newIdx=tabOrder.indexOf(t);curTab=t;document.querySelectorAll('.pg,.sub').forEach(function(p){p.classList.remove('on','slide-in-right','slide-in-left')});var pg=document.getElementById('pg-'+t);pg.classList.add('on');if(newIdx>oldIdx)pg.classList.add('slide-in-right');else if(newIdx<oldIdx)pg.classList.add('slide-in-left');document.querySelectorAll('.bn').forEach(function(b){b.classList.toggle('on',b.dataset.p===t)});window.scrollTo({top:0,behavior:'smooth'});if(t==='schedule')renderCal()}
