/* ═══ 캘린더 ═══ */
var calY,calMo,calSel;
function initCal(){var n=new Date();calY=n.getFullYear();calMo=n.getMonth();calSel=n.toISOString().slice(0,10)}
function renderCal(){document.getElementById('calMonth').textContent=calY+'년 '+(calMo+1)+'월';var dows=['일','월','화','수','목','금','토'];document.getElementById('calDow').innerHTML=dows.map(function(d){return'<div class="cal-dow">'+d+'</div>'}).join('');var first=new Date(calY,calMo,1),last=new Date(calY,calMo+1,0).getDate(),sd=first.getDay();var today=new Date().toISOString().slice(0,10);var html='';for(var i=0;i<sd;i++)html+='<div class="cal-day emp"></div>';for(var d=1;d<=last;d++){var ds=calY+'-'+String(calMo+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');var cls='cal-day';if(ds===today)cls+=' today';else if(ds===calSel)cls+=' sel';if((D.events[ds]||[]).length>0)cls+=' has';html+='<div class="'+cls+'" onclick="selDay(\''+ds+'\')">'+d+'</div>'}document.getElementById('calGrid').innerHTML=html;renderDdays();renderTimeline()}
function selDay(ds){calSel=ds;renderCal();renderTimeline()}

/* ═══ D-day ═══ */
function renderDdays(){var s=document.getElementById('ddayStrip');if(!s)return;if(!D.ddays||!D.ddays.length){s.innerHTML='<div style="font-size:13px;color:var(--t4);padding:8px 0">D-day를 추가해보세요</div>';return}var today=new Date();today.setHours(0,0,0,0);D.ddays.sort(function(a,b){return new Date(a.date)-new Date(b.date)});s.innerHTML=D.ddays.map(function(d){var dd=new Date(d.date);dd.setHours(0,0,0,0);var diff=Math.ceil((dd-today)/86400000);return'<div class="dday-chip"><div class="'+(diff<=7?'dday-num':'dday-num far')+'">'+(diff===0?'D-Day':diff>0?'D-'+diff:'D+'+Math.abs(diff))+'</div><div style="flex:1"><div style="font-size:13px;font-weight:600">'+d.name+'</div><div style="font-size:11px;color:var(--t4)">'+(dd.getMonth()+1)+'월 '+dd.getDate()+'일</div></div><button class="dday-del" onclick="delDday(\''+d.id+'\')">✕</button></div>'}).join('')}
function addDday(){var nm=document.getElementById('ddayName').value.trim(),dt=document.getElementById('ddayDate').value;if(!nm||!dt){alert('이름과 날짜를 입력해줘!');return}if(!D.ddays)D.ddays=[];D.ddays.push({id:'dd'+Date.now(),name:nm,date:dt});closeModal('ddayModal');document.getElementById('ddayName').value='';document.getElementById('ddayDate').value='';renderDdays();SS.save()}
function delDday(id){D.ddays=D.ddays.filter(function(d){return d.id!==id});renderDdays();SS.save()}

/* ═══ 일정 ═══ */
var evtCat='study';
function addEvent(){var title=document.getElementById('evtTitle').value.trim();var ts=document.getElementById('evtTimeStart').value,te=document.getElementById('evtTimeEnd').value;var customCat=document.getElementById('evtCustomCat');var cat=evtCat==='custom'&&customCat?customCat.value.trim()||'기타':evtCat;if(!title){alert('할 일을 입력해줘!');return}if(!D.events[calSel])D.events[calSel]=[];D.events[calSel].push({id:'ev'+Date.now(),title:title,timeStart:ts,timeEnd:te,cat:cat,priority:'normal',done:false,memo:'',checklist:[]});closeModal('addEventModal');document.getElementById('evtTitle').value='';renderCal();updateHomeTodos();renderTimeline();SS.save()}
function togEvent(date,id){var evts=D.events[date];if(!evts)return;var ev=evts.find(function(e){return e.id===id});if(ev)ev.done=!ev.done;renderTimeline();updateHomeTodos();SS.save()}

/* ═══ 일정 상세 ═══ */
function openEvtDetail(dateKey,evtId){var evts=D.events[dateKey]||[];var evt=evts.find(function(e){return e.id===evtId});if(!evt)return;var card=document.getElementById('evtDetailCard');var cats=[{k:'study',l:'학습'},{k:'career',l:'진로'},{k:'habit',l:'습관'},{k:'etc',l:'기타'}];var pris=[{k:'urgent',l:'🔴 긴급'},{k:'important',l:'🟡 중요'},{k:'normal',l:'🔵 보통'},{k:'low',l:'⚪ 낮음'}];var catClass=(['study','career','habit','etc'].indexOf(evt.cat)>=0)?evt.cat:'custom';
card.innerHTML='<div class="ed-header"><div class="ed-cat-dot '+catClass+'"></div><textarea class="ed-title" id="edTitle" rows="1">'+evt.title+'</textarea><button class="ed-close" id="edClose">✕</button></div><div class="ed-meta"><div class="ed-meta-row"><div class="ed-meta-icon">📂</div><div class="ed-meta-label">카테고리</div><div class="ed-meta-val"><select id="edCat">'+cats.map(function(c){return'<option value="'+c.k+'"'+(evt.cat===c.k?' selected':'')+'>'+c.l+'</option>'}).join('')+'</select></div></div><div class="ed-meta-row"><div class="ed-meta-icon">⏰</div><div class="ed-meta-label">시간</div><div class="ed-meta-val"><input type="time" id="edTimeS" value="'+(evt.timeStart||'09:00')+'"> ~ <input type="time" id="edTimeE" value="'+(evt.timeEnd||'10:00')+'"></div></div><div class="ed-meta-row"><div class="ed-meta-icon">🔥</div><div class="ed-meta-label">우선순위</div><div class="ed-meta-val"><div class="ed-priority" id="edPri">'+pris.map(function(p){return'<button class="ed-pri'+(evt.priority===p.k?' on ':' ')+p.k+'" data-pri="'+p.k+'">'+p.l+'</button>'}).join('')+'</div></div></div></div><div class="ed-divider"></div><div class="ed-memo"><textarea class="ed-memo-area" id="edMemo" placeholder="메모를 자유롭게 작성해봐...">'+(evt.memo||'')+'</textarea></div><div class="ed-divider"></div><div class="ed-checklist"><div class="ed-check-title">☑️ 체크리스트</div><div id="edChecks">'+(evt.checklist||[]).map(function(c,i){return'<div class="ed-check-item"><button class="ed-ck'+(c.done?' dn':'')+'" data-ci="'+i+'">'+(c.done?'✓':'')+'</button><input class="ed-check-text'+(c.done?' x':'')+'" value="'+c.text+'" data-ci="'+i+'"><button class="ed-check-del" data-ci="'+i+'">✕</button></div>'}).join('')+'</div><button class="ed-add-check" id="edAddCheck">+ 체크리스트 추가</button></div><div class="ed-footer"><button class="ed-save" id="edSave">저장</button><button class="ed-delete" id="edDelete">삭제</button></div>';
document.getElementById('evtDetail').classList.add('on');
document.getElementById('edClose').onclick=closeEvtDetail;document.getElementById('edSave').onclick=function(){saveEvtDetail(dateKey,evtId)};document.getElementById('edDelete').onclick=function(){if(!confirm('삭제할까?'))return;D.events[dateKey]=D.events[dateKey].filter(function(e){return e.id!==evtId});closeEvtDetail();renderCal();updateHomeTodos();renderTimeline();SS.save()};
document.getElementById('edAddCheck').onclick=function(){var checks=document.getElementById('edChecks');var div=document.createElement('div');div.className='ed-check-item';div.innerHTML='<button class="ed-ck"></button><input class="ed-check-text" placeholder="할 일 입력..."><button class="ed-check-del">✕</button>';checks.appendChild(div);bindCheckEvents(div)};
document.querySelectorAll('#edPri .ed-pri').forEach(function(btn){btn.onclick=function(){document.querySelectorAll('#edPri .ed-pri').forEach(function(b){b.classList.remove('on')});this.classList.add('on')}});
document.querySelectorAll('#edChecks .ed-check-item').forEach(function(item){bindCheckEvents(item)})}
function bindCheckEvents(item){var ck=item.querySelector('.ed-ck'),del=item.querySelector('.ed-check-del');if(ck)ck.onclick=function(){this.classList.toggle('dn');this.textContent=this.classList.contains('dn')?'✓':'';var inp=item.querySelector('.ed-check-text');if(inp)inp.classList.toggle('x',this.classList.contains('dn'))};if(del)del.onclick=function(){item.remove()}}
function saveEvtDetail(dateKey,evtId){var evts=D.events[dateKey]||[];var evt=evts.find(function(e){return e.id===evtId});if(!evt)return;evt.title=document.getElementById('edTitle').value.trim()||evt.title;evt.cat=document.getElementById('edCat').value;evt.timeStart=document.getElementById('edTimeS').value;evt.timeEnd=document.getElementById('edTimeE').value;evt.memo=document.getElementById('edMemo').value;var priBtn=document.querySelector('#edPri .ed-pri.on');if(priBtn)evt.priority=priBtn.dataset.pri;var checks=[];document.querySelectorAll('#edChecks .ed-check-item').forEach(function(item){var inp=item.querySelector('.ed-check-text'),ck=item.querySelector('.ed-ck');if(inp&&inp.value.trim())checks.push({text:inp.value.trim(),done:ck&&ck.classList.contains('dn')})});evt.checklist=checks;closeEvtDetail();renderCal();updateHomeTodos();renderTimeline();SS.save()}
function closeEvtDetail(){document.getElementById('evtDetail').classList.remove('on')}

/* ═══ 타임라인 ═══ */
function renderTimeline(){var el=document.getElementById('tlItems');if(!el)return;var evts=(D.events[calSel]||[]).slice().sort(function(a,b){return(a.timeStart||'').localeCompare(b.timeStart||'')});var today=new Date().toISOString().slice(0,10);var ds=new Date(calSel);var days=['일','월','화','수','목','금','토'];document.getElementById('tlDate').textContent=calSel===today?'오늘의 일정':(ds.getMonth()+1)+'월 '+ds.getDate()+'일 ('+days[ds.getDay()]+')';
if(!evts.length){el.innerHTML='<div class="empty"><div class="empty-icon">📋</div><div class="empty-text">일정을 추가하거나<br>브레인덤프로 정리해보세요</div></div>';updateDaySummary(0,0);return}
var dn=evts.filter(function(e){return e.done}).length;var priEmoji={urgent:'🔴',important:'🟡',normal:'🔵',low:'⚪'};el.innerHTML=evts.map(function(e,i){var isLast=i===evts.length-1;var catClass=(['study','career','habit','etc'].indexOf(e.cat)>=0)?e.cat:'custom';return'<div class="tl-item"><div class="tl-time">'+(e.timeStart||'')+'</div><div class="tl-dot-col"><div class="tl-dot'+(e.done?' done':'')+'"></div>'+(isLast?'':'<div class="tl-line"></div>')+'</div><div class="tl-card" data-date="'+calSel+'" data-evid="'+e.id+'"><div class="tl-card-cat '+catClass+'"></div><div class="tl-card-info"><div class="tl-card-title'+(e.done?' x':'')+'">'+e.title+'</div><div class="tl-card-sub">'+(e.timeStart||'')+' ~ '+(e.timeEnd||'')+' '+(priEmoji[e.priority]||'')+'</div></div><button class="tl-card-ck'+(e.done?' dn':'')+'" data-date="'+calSel+'" data-evid="'+e.id+'">'+(e.done?'✓':'')+'</button></div></div>'}).join('');
el.querySelectorAll('.tl-card').forEach(function(card){card.onclick=function(ev){if(ev.target.classList.contains('tl-card-ck'))return;openEvtDetail(this.dataset.date,this.dataset.evid)}});
el.querySelectorAll('.tl-card-ck').forEach(function(btn){btn.onclick=function(ev){ev.stopPropagation();togEvent(this.dataset.date,this.dataset.evid)}});
updateDaySummary(dn,evts.length)}
function updateDaySummary(done,total){var pct=total?Math.round(done/total*100):0;document.getElementById('dayPct').textContent=pct+'%';document.getElementById('dayArc').setAttribute('stroke-dashoffset',138-138*(pct/100));document.getElementById('dayMeta').textContent='일정 '+total+'개 중 '+done+'개 완료';var dt=new Date(calSel);document.getElementById('dayTitle').textContent=(dt.getMonth()+1)+'/'+dt.getDate()+' 달성률'}

/* ═══ 홈 투두 ═══ */
function updateHomeTodos(){var today=new Date().toISOString().slice(0,10);var evts=(D.events[today]||[]).slice().sort(function(a,b){return(a.timeStart||'').localeCompare(b.timeStart||'')});var el=document.getElementById('todoList'),cnt=document.getElementById('todoCount');if(!el)return;cnt.textContent=evts.length+'개';if(!evts.length){el.innerHTML='<div class="empty" style="padding:24px"><div class="empty-text">브레인덤프로 할 일을 추가해보세요</div></div>';return}el.innerHTML=evts.map(function(e){return'<div class="todo-item" data-date="'+today+'" data-evid="'+e.id+'"><button class="todo-ck'+(e.done?' dn':'')+'">'+(e.done?'✓':'')+'</button><div class="todo-txt'+(e.done?' x':'')+'">'+e.title+'</div><div class="todo-time">'+(e.timeStart||'')+'</div></div>'}).join('');el.querySelectorAll('.todo-item').forEach(function(item){item.onclick=function(ev){if(ev.target.classList.contains('todo-ck')){togEvent(this.dataset.date,this.dataset.evid);return}openEvtDetail(this.dataset.date,this.dataset.evid)}})}

/* ═══ 모달 ═══ */
function openModal(id){document.getElementById(id).classList.add('on')}
function closeModal(id){document.getElementById(id).classList.remove('on')}

/* ═══ 브레인덤프 ═══ */
var bdParsed=[],bdStep=0;
function bdStart(){bdStep=0;bdParsed=[];document.getElementById('bdPage').classList.add('on');bdRenderStep()}
function bdClose(){document.getElementById('bdPage').classList.remove('on')}
function bdRenderStep(){var body=document.getElementById('bdBody'),footer=document.getElementById('bdFooter');for(var i=0;i<3;i++){var d=document.getElementById('bdP'+i);if(i<bdStep)d.className='bd-prog-dot done';else if(i===bdStep)d.className='bd-prog-dot on';else d.className='bd-prog-dot'}document.getElementById('bdStepInd').textContent=(bdStep+1)+'/3';
if(bdStep===0){body.innerHTML='<div class="bd-guide">🧠 머릿속에 있는 할 일을 전부 쏟아내봐!<br>한 줄에 하나씩!</div><textarea class="bd-textarea" id="bdRaw" placeholder="수학 2단원 풀기\n영어 단어 외우기\n방 정리하기"></textarea>';footer.innerHTML='<button class="ob-btn" id="bdNext1">다음: 분류하기 →</button>';document.getElementById('bdNext1').onclick=bdToStep2}
else if(bdStep===1){var cats=[{k:'study',l:'📘학습'},{k:'career',l:'🧭진로'},{k:'habit',l:'🔄습관'},{k:'etc',l:'📌기타'}];var pris=[{k:'urgent',l:'🔴긴급'},{k:'important',l:'🟡중요'},{k:'normal',l:'🔵보통'},{k:'low',l:'⚪낮음'}];body.innerHTML='<div class="bd-guide">📋 각 항목의 카테고리와 우선순위를 정해줘!</div>'+bdParsed.map(function(item,i){return'<div class="bd-item"><div class="bd-item-title">'+item.title+'</div><div class="bd-item-row"><div style="display:flex;gap:4px;flex-wrap:wrap">'+cats.map(function(c){return'<button class="bd-item-pill'+(item.cat===c.k?' on':'')+'" data-idx="'+i+'" data-cat="'+c.k+'">'+c.l+'</button>'}).join('')+'</div></div><div class="bd-item-row" style="margin-top:4px"><div style="display:flex;gap:4px">'+pris.map(function(p){return'<button class="bd-pri'+(item.priority===p.k?' on '+p.k:'')+'" data-idx="'+i+'" data-pri="'+p.k+'">'+p.l+'</button>'}).join('')+'</div></div></div>'}).join('');footer.innerHTML='<button class="ob-btn" id="bdNext2">다음: 시간 배치 →</button>';document.getElementById('bdNext2').onclick=bdToStep3;body.querySelectorAll('.bd-item-pill').forEach(function(btn){btn.onclick=function(){var idx=parseInt(this.dataset.idx);bdParsed[idx].cat=this.dataset.cat;this.parentElement.querySelectorAll('.bd-item-pill').forEach(function(p){p.classList.remove('on')});this.classList.add('on')}});body.querySelectorAll('.bd-pri').forEach(function(btn){btn.onclick=function(){var idx=parseInt(this.dataset.idx);bdParsed[idx].priority=this.dataset.pri;this.parentElement.querySelectorAll('.bd-pri').forEach(function(p){p.classList.remove('on');p.className=p.className.replace(/urgent|important|normal|low/g,'').trim()});this.classList.add('on',this.dataset.pri)}})}
else if(bdStep===2){var catEmoji={study:'📘',career:'🧭',habit:'🔄',etc:'📌'};body.innerHTML='<div class="bd-guide">⏰ 각 항목의 시간을 정해줘!</div>'+bdParsed.map(function(item,i){return'<div class="bd-item"><div class="bd-item-title">'+(catEmoji[item.cat]||'📌')+' '+item.title+'</div><div class="bd-time-row"><input type="time" class="bd-time-input" value="'+item.timeStart+'" data-idx="'+i+'" data-field="timeStart"><span class="bd-time-sep">~</span><input type="time" class="bd-time-input" value="'+item.timeEnd+'" data-idx="'+i+'" data-field="timeEnd"></div></div>'}).join('');footer.innerHTML='<button class="ob-btn" id="bdFinish">완료 → 일정에 추가</button>';document.getElementById('bdFinish').onclick=bdComplete;body.querySelectorAll('.bd-time-input').forEach(function(inp){inp.onchange=function(){bdParsed[parseInt(this.dataset.idx)][this.dataset.field]=this.value}})}}
function bdToStep2(){var raw=document.getElementById('bdRaw').value.trim();if(!raw){alert('할 일을 입력해줘!');return}bdParsed=raw.split('\n').filter(function(l){return l.trim()}).map(function(l,i){return{id:'bd'+Date.now()+i,title:l.trim(),cat:'study',priority:'normal',timeStart:String(9+i).padStart(2,'0')+':00',timeEnd:String(10+i).padStart(2,'0')+':00',memo:'',checklist:[]}});bdStep=1;bdRenderStep()}
function bdToStep3(){bdStep=2;bdRenderStep()}
function bdComplete(){if(!D.events[calSel])D.events[calSel]=[];bdParsed.forEach(function(item){D.events[calSel].push({id:item.id,title:item.title,timeStart:item.timeStart,timeEnd:item.timeEnd,cat:item.cat,priority:item.priority,done:false,memo:'',checklist:[]})});bdClose();bdParsed=[];renderCal();updateHomeTodos();renderTimeline();handleEXP('braindump');SS.save()}

/* ═══ 시간표 ═══ */
function openTimePanel(){document.getElementById('tpOverlay').classList.add('on');document.getElementById('tpPanel').classList.add('on');renderTimePanel()}
function closeTimePanel(){document.getElementById('tpOverlay').classList.remove('on');document.getElementById('tpPanel').classList.remove('on')}
function renderTimePanel(){var grid=document.getElementById('tpGrid');if(!grid)return;var evts=(D.events[calSel]||[]);var ds=new Date(calSel);document.getElementById('tpTitle').textContent=(ds.getMonth()+1)+'월 '+ds.getDate()+'일 시간표';var html='';for(var h=6;h<24;h++){html+='<div class="tp-slot" data-hour="'+h+'"><div class="tp-slot-label">'+String(h).padStart(2,'0')+':00</div>';evts.forEach(function(e){var ts=e.timeStart||'';if(!ts)return;var sh=parseInt(ts.split(':')[0]);if(h===sh){var te=e.timeEnd||'';var eh=te?parseInt(te.split(':')[0]):sh+1;var dur=Math.max(1,eh-sh);var bh=Math.max(28,dur*48-4);var catClass=(['study','career','habit','etc'].indexOf(e.cat)>=0)?e.cat:'custom';html+='<div class="tp-block '+catClass+'" style="height:'+bh+'px" data-date="'+calSel+'" data-evid="'+e.id+'"><div class="tp-block-title">'+e.title+'</div><div class="tp-block-time">'+ts+' ~ '+te+'</div></div>'}});html+='</div>'}grid.innerHTML=html;
grid.querySelectorAll('.tp-slot').forEach(function(slot){slot.onclick=function(ev){if(ev.target.closest('.tp-block'))return;var h=this.dataset.hour;document.getElementById('evtTimeStart').value=String(h).padStart(2,'0')+':00';document.getElementById('evtTimeEnd').value=String(parseInt(h)+1).padStart(2,'0')+':00';closeTimePanel();openModal('addEventModal')}});
grid.querySelectorAll('.tp-block').forEach(function(block){block.onclick=function(ev){ev.stopPropagation();openEvtDetail(this.dataset.date,this.dataset.evid)}})}

/* ═══ 소개 슬라이드 ═══ */
var introIdx=0;
function showIntroSlides(){introIdx=0;document.getElementById('obIntro').style.display='flex';updateIntroSlide()}
function updateIntroSlide(){var slides=document.querySelectorAll('.ob-intro-slide');var dots=document.querySelectorAll('.ob-intro-dot');slides.forEach(function(s,i){s.classList.remove('active','left');if(i<introIdx)s.classList.add('left');else if(i===introIdx)s.classList.add('active')});dots.forEach(function(d,i){d.classList.toggle('on',i===introIdx)});document.getElementById('introNextBtn').textContent=introIdx>=slides.length-1?'시작하기':'다음'}
function nextIntroSlide(){if(introIdx>=document.querySelectorAll('.ob-intro-slide').length-1)closeIntroSlides();else{introIdx++;updateIntroSlide()}}
function closeIntroSlides(){var el=document.getElementById('obIntro');el.classList.add('out');setTimeout(function(){el.style.display='none';el.classList.remove('out')},400)}

/* ═══ initApp ═══ */
function initApp(){if(D.events)Object.keys(D.events).forEach(function(dk){(D.events[dk]||[]).forEach(function(ev){if(ev.time&&!ev.timeStart){ev.timeStart=ev.time;delete ev.time}if(!ev.priority)ev.priority='normal';if(!ev.memo)ev.memo='';if(!ev.checklist)ev.checklist=[]})});
initRPG();if(!D.favorites)D.favorites=[];if(!D.ddays)D.ddays=[];if(!D.events)D.events={};if(!D.user.earnedTitles)D.user.earnedTitles=[];if(!D.activityLog)D.activityLog={};
initCal();updateHome();renderCal();updateDonut();updateHomeTodos();renderTimeline();renderSD();renderVals();renderJournal();renderRoutines();renderChallenges();initEvScales();renderTitles();renderRecords();
var td=new Date().toISOString().slice(0,10);if(!D.activityLog[td]){D.activityLog[td]=1;D.user.days++;handleEXP('login')}
checkTitles();SS.save()}

